        value = color.strip().lower().replace(" ", "_")
        if not value:
            raise StyleSyntaxError("empty color")
        if value == "default":
            return cls("default", NAMED_COLORS["default"])
        if value in NAMED_COLORS:
            return cls(value, NAMED_COLORS[value])
        match = re.fullmatch(r"color\((\d{1,3})\)", value)
        if match:
            number = int(match.group(1))
            if not 0 <= number <= 255:
                raise StyleSyntaxError(f"color number out of range: {number}")
            return cls(f"color({number})", number=number)
        match = re.fullmatch(r"#?([0-9a-f]{6})", value)
        if match:
            raw = match.group(1)
            return cls("#" + raw, (int(raw[:2], 16), int(raw[2:4], 16), int(raw[4:], 16)))
        match = re.fullmatch(r"rgb\((\d{1,3}),(\d{1,3}),(\d{1,3})\)", value.replace(" ", ""))
        if match:
            rgb = tuple(int(part) for part in match.groups())
            if any(part > 255 for part in rgb):
